import { AUTOEXEC_CATEGORIES, AUTOEXEC_SETTINGS } from "./autoexec-settings.js";
import { toConsoleCommands } from "./crosshair.js";

const FILE_HEADER = `// ============================================================
// CS2 autoexec.cfg — generated by Crosshair Generator
// Path: .../Counter-Strike Global Offensive/game/csgo/cfg/autoexec.cfg
// Steam launch options: +exec autoexec.cfg
// ============================================================
`;

function formatValue(value, type) {
  if (type === "bool") {
    return value ? "1" : "0";
  }
  return String(value);
}

function parseCrosshairCommands(crosshair) {
  return toConsoleCommands(crosshair)
    .split("\n")
    .map((line) => line.trim())
    .filter(Boolean)
    .map((line) => {
      const match = line.match(/^(\S+)\s+"([^"]*)"$/);
      if (!match) {
        return null;
      }
      return { command: match[1], value: match[2] };
    })
    .filter(Boolean);
}

export function generateAutoexec(crosshair, autoexecState) {
  const lines = [FILE_HEADER.trimEnd(), ""];

  AUTOEXEC_CATEGORIES.forEach((category) => {
    if (!autoexecState.enabled[category.id]) {
      return;
    }

    lines.push(`// ----- ${category.label} -----`);
    lines.push(`// ${category.description}`);

    if (category.id === "crosshair") {
      parseCrosshairCommands(crosshair).forEach(({ command, value }) => {
        lines.push(`${command} "${value}"`);
      });
      lines.push("");
      return;
    }

    AUTOEXEC_SETTINGS.filter((setting) => setting.category === category.id).forEach((setting) => {
      if (!autoexecState.enabled[setting.id]) {
        return;
      }
      const value = formatValue(autoexecState.values[setting.id], setting.type);
      lines.push(`${setting.command} "${value}"`);
    });

    lines.push("");
  });

  lines.push('echo "autoexec.cfg loaded"');
  return `${lines.join("\n").trimEnd()}\n`;
}

export function getSettingsByCategory(categoryId) {
  return AUTOEXEC_SETTINGS.filter((setting) => setting.category === categoryId);
}
